mapper.select:
SELECT bill_company_id, company_nm, representative_nm, biz_no, address, post_no, biz_type, biz_item, tel_no, fax_no, email, bank_nm, depositor_nm, account_no, rmk, reg_id, reg_dt, chg_id, chg_dt, del_yn FROM bill_company WHERE del_yn = 'N'
AND bill_company_id = #{billCompanyId}
AND company_nm LIKE CONCAT('%', #{companyNm}, '%')
AND biz_no = #{bizNo}
order by bill_company_id desc
